%[text] # `Compare: Uninterrupted, Segmented, & Independent Traces:`
%%
%[text] ## `Configure MATLAB:`
restoredefaultpath;    clear;    close all;    clc;    addpath(genpath(fileparts(mfilename('fullpath')))) % In case "Configure" is not available.
Configure
Seed = 22;    rng(Seed, "Twister");
%%
%[text] ## `Generate Data:`
%[text] ## `Set HMM(3) Parameters:`
%[text]  `Transition Matrix` $\\mathbf{\\Pi}\n\\equiv\\{\\mathbf{\\pi}\_{\\sigma\_{m}}\\}\n\\equiv\\{\\pi\_{\\sigma\_{m}\\to\\sigma\_{m^{\\prime}}}\\}\n\\in\[0,1\]^{M \\times M}$`:`
GT.TransitionMatrix       = [0.88 0.08 0.04 ;
                             0.06 0.90 0.04 ;
                             0.02 0.05 0.93];
%[text]  `Stationary Distribution` $\\mathbf{\\varrho}=\\mathbf{\\varrho}\\mathbf{\\Pi}$`:` 
GT.StationaryDistribution = getStationaryDistribution(GT.TransitionMatrix);
%[text]  `Emission Model` $\\mathbb{P}(w\_{n}\\,|\\,s\_{n},\\phi\_{s\_{n}})$`:`
GT.Means                  = [-2, 0, 2]       ;
GT.Variance               = 0.09             ;
GT.StandardDeviation      = sqrt(GT.Variance);

% Infer pi(1,2); Hold Other Entries Fixed at GT.
Fixed.p13 = GT.TransitionMatrix(1,3);
Fixed.p21 = GT.TransitionMatrix(2,1);
Fixed.p23 = GT.TransitionMatrix(2,3);
Fixed.p31 = GT.TransitionMatrix(3,1);
Fixed.p32 = GT.TransitionMatrix(3,2);
%[text] ### `Gap Regimes:`
% Report Mean Gaps in Units of the Mean Dwell Time:
 Tau    = 1 / (1 - GT.TransitionMatrix(1,1));
 GapTau = [1/8; 1; 8]                       ;

Regimes.meanGapFrames = GapTau * Tau              ;
Regimes.geomProb      = 1 ./ Regimes.meanGapFrames;
nRegimes              = numel(GapTau)             ;
%[text] ### `Set Data Acquisition Parameters:`
N = 1000; % Retained Observations per Regime
R = 1   ; % Schedule Replicates

% Observation Schedule:
tIndex = cell(nRegimes, R);
Tmax   = 0;
for r = 1 : nRegimes
    pGeom = Regimes.geomProb(r);
    for rep = 1 : R
        tIndex{r,rep} = geometricTimes(N, pGeom);
        Tmax = max(Tmax, tIndex{r,rep}(end));
    end
end
%[text] #### `Uninterrupted Trace:` $\\mathbf{\\mathit{w}}$
[Full.s, Full.w] = simulateHMM_K(Tmax + 50, GT.StationaryDistribution, GT.TransitionMatrix, GT.Means, GT.StandardDeviation);
%%
%[text] ## `Analyze Data:`
%[text] ####  Parameter `Grid:`
p12Min    =                 1e-3;
p12Max    = 1 - Fixed.p13 - 1e-3; % Ensure Row 1 Remains Stochastic
nGrid     = 600                 ;
Grid.p12  = linspace(p12Min, p12Max, nGrid)                     ;
Prior.p12 = ones(size(Grid.p12)) / (Grid.p12(end) - Grid.p12(1));
%[text] ### `Marginal Posterior:`
PosteriorAnalytic    = zeros(nRegimes, nGrid);
PosteriorStationary  = zeros(nRegimes, nGrid);
PosteriorIndependent = zeros(nRegimes, nGrid);

Summary(nRegimes,1) = struct("gapTau",[], "meanGapFrames",[], "Nobs",[], "Lengths",[]);

for r                     = 1 : nRegimes
    rPosteriorAnalytic    = zeros(1, nGrid);
    rPosteriorStationary  = zeros(1, nGrid);
    rPosteriorIndependent = zeros(1, nGrid);

  for rep = 1 : R
      ti  = tIndex{r,rep}(:).'; % Retained Times on the Full Latent Grid
      w   = Full.w(ti).'      ; % Retained Observations

      % Observed Segments are Maximal Contiguous Runs in the Retained Record.
      [Starts, Ends] = scheduleSegments(ti);
      Lengths        = Ends - Starts + 1   ;
%[text] #### `Matched Independent Traces:` $\\mathbf{{u}$
      % Matched Independent Trace Control:
      uChunks = simulateIndependentTraces(Lengths, GT.StationaryDistribution, GT.TransitionMatrix, GT.Means, GT.StandardDeviation);

      logPosteriorAnalytic    = -Inf(1, nGrid);
      logPosteriorStationary  = -Inf(1, nGrid);
      logPosteriorIndependent = -Inf(1, nGrid);

      for i = 1 : nGrid
          TransitionMatrix = fixTransitionMatrixElements(Grid.p12(i), Fixed);
          if any(TransitionMatrix(:) < -1e-12) || any(abs(sum(TransitionMatrix,2) - 1) > 1e-12);    continue;    end

          % Initialize from the Stationary Distribution of the Candidate Matrix.
          StationaryDistribution = getStationaryDistribution(TransitionMatrix);
          EmissionModel          = @(w, s) pdfGaussian(w, GT.Means(s), GT.StandardDeviation);
%[text] #### $\\mathbb{P}(\\mathbf{\\vartheta} \\,|\\, \\mathbf{\\mathit{w}},\\mathbf{\\phi},\\mathbf{\\mathit{g}})$
          % Exact Observed-Data Likelihood (Propagates Analytic Bridge):
          logPosteriorAnalytic(i) = forwardAnalytic(w, ti, StationaryDistribution, TransitionMatrix, EmissionModel);
%[text] #### $\\mathbb{P}(\\mathbf{\\vartheta} \\,|\\, \\widetilde{\\mathbf{{w}}},\\mathbf{\\phi})$
          % Stationary Restart Approximation:
          logPosteriorStationary(i) = forwardStationary(w, ti, TransitionMatrix, EmissionModel);
%[text] #### $\\mathbb{P}(\\mathbf{\\vartheta} \\,|\\, \\mathbf{{u},\\mathbf{\\phi})$
          % Matched Independent Control:
          logPosteriorIndependent(i) = forwardIndependent(uChunks, TransitionMatrix, EmissionModel);
      end

      PostAnalytic    = normalizeLogVector(logPosteriorAnalytic   , Grid.p12);
      PostStationary  = normalizeLogVector(logPosteriorStationary , Grid.p12);
      PostIndependent = normalizeLogVector(logPosteriorIndependent, Grid.p12);

      rPosteriorAnalytic    = rPosteriorAnalytic    + PostAnalytic   ;
      rPosteriorStationary  = rPosteriorStationary  + PostStationary ;
      rPosteriorIndependent = rPosteriorIndependent + PostIndependent;

      Summary(r).Lengths    = Lengths                                ;
  end

  PosteriorAnalytic   (r,:) = rPosteriorAnalytic    / R;
  PosteriorStationary (r,:) = rPosteriorStationary  / R;
  PosteriorIndependent(r,:) = rPosteriorIndependent / R;

  Summary(r).gapTau        = GapTau(r)               ;
  Summary(r).meanGapFrames = Regimes.meanGapFrames(r);
  Summary(r).Nobs          = N                       ;
end
%%
save("Data/Data(Gaps,Seed="+Seed+",N="+N+",Scale="+GapTau(end)+").mat", 'GT', 'Fixed', 'Tau', 'GapTau', 'Regimes', 'Grid', 'Prior', 'PosteriorAnalytic', 'PosteriorStationary', 'PosteriorIndependent', 'Summary', 'nRegimes');
%%
nRegimes = length(Regimes.geomProb);

Color.Analytic    = [0.671 0.086 0.086];
Color.Stationary  = [0.867 0.329 0.000];
Color.Independent = [0.929 0.694 0.125];
Color.Prior       = [0.067 0.443 0.745];
Color.True        = [0.231 0.667 0.196];

LineWidth =  2;
FontSize  = 16;

Figure = figure("Name",'Figure(5)', "Position", [70 70 1400 460]); %[output:1cc9ac12]
Tiles  = tiledlayout(Figure, 3, nRegimes, "TileSpacing",'Compact', "Padding",'Compact'); %[output:1cc9ac12]

GTp12   = GT.TransitionMatrix(1,2);
maxYAll = max([PosteriorAnalytic(:); PosteriorStationary(:); PosteriorIndependent(:); Prior.p12(:)]);

for r = 1 : nRegimes %[output:group:4375ccd2]
    Axes = nexttile(Tiles); %[output:1cc9ac12]
    hold(Axes, "On");
    Axes.FontSize = FontSize;


    plot(Axes, Grid.p12, PosteriorAnalytic(r,:)   , "Color",Color.Analytic   , "LineWidth",LineWidth    , "DisplayName","ℙ(𝝑 | 𝙬,𝙜)");
    plot(Axes, Grid.p12, PosteriorStationary(r,:) , "Color",Color.Stationary , "LineWidth",LineWidth    , "DisplayName","ℙ(𝝑 | 𝙬͂)")  ;
    plot(Axes, Grid.p12, PosteriorIndependent(r,:), "Color",Color.Independent, "LineWidth",LineWidth    , "DisplayName","ℙ(𝝑 | 𝘂)")   ;
    plot(Axes, Grid.p12, Prior.p12                , "Color",Color.Prior      , "LineWidth",LineWidth-1/2, "DisplayName","ℙ(𝝑)")       ;
    xline(Axes, GTp12, '--',                        "Color",Color.True       , "LineWidth",LineWidth-1  , "DisplayName","GT 𝝑")       ;

    grid(Axes, "Off");
    box(Axes, "On");
    xlim(Axes, [Grid.p12(1), Grid.p12(end)]);
    ylim(Axes, [0, 1.05 * maxYAll]);

%    title(Axes, sprintf('$\\langle g \\rangle = %s\\tau$', num2str(GapTau(r), '%g')));
%    xlabel(Axes, '$\pi_{\sigma_1\to\sigma_2}$');

    if     r == 1;    text(Axes, 0,1, "$\langle{g}\rangle = \tau / 8$", "Interpreter",'LaTeX', "HorizontalAlignment",'Left',"VerticalAlignment",'Top', "Units",'Normalized', "FontSize",FontSize);    
    elseif r == 2;    text(Axes, 0,1, "$\langle{g}\rangle = \tau$"    , "Interpreter",'LaTeX', "HorizontalAlignment",'Left',"VerticalAlignment",'Top', "Units",'Normalized', "FontSize",FontSize);    
    elseif r == 3;    text(Axes, 0,1, "$\langle{g}\rangle = 8\tau$"   , "Interpreter",'LaTeX', "HorizontalAlignment",'Left',"VerticalAlignment",'Top', "Units",'Normalized', "FontSize",FontSize);    
    end

    if r == 1;    ylabel(Axes, "Density");    end
    if r == 2;    Legend = legend(Axes, "Location",'NorthOutside', "Box",'Off', "Orientation",'Horizontal', "FontSize",FontSize);    end

    xlim(Axes, [1/24  1/8])
    Axes.XTick = linspace(Axes.XLim(1), Axes.XLim(2), 3);%[0,1/8,1/4];

    Axes.XTickLabel = {"1/24","$\pi_{\sigma_1\to\sigma_2}$","1/4"};
    Axes.YTickLabel = {};

end %[output:group:4375ccd2]
%%
Seed =   22;
N    = 1000;
print(Figure, "Results(Gaps,Seed="+Seed+",N="+N+",Scale="+GapTau(end)+")", '-dpng', '-r350');
%%
function TransitionMatrix = fixTransitionMatrixElements(p12, Fixed)
% Build 3x3 Row-Stochastic Matrix from p12 while Holding Other Entries Fixed.
    p13 = Fixed.p13;
    p21 = Fixed.p21;    p23 = Fixed.p23;
    p31 = Fixed.p31;    p32 = Fixed.p32;

    TransitionMatrix = [1-p12-p13,     p12   ,    p13     ;
                          p21    ,  1-p21-p23,        p23 ;
                          p31    ,        p32,  1-p31-p32];
end

function piRow = getStationaryDistribution(TransitionMatrix)
% Compute the Stationary Distribution as the Normalized Left Eigenvector at lambda=1.
    [V, D]     = eig(TransitionMatrix.');
    [~, Index] = min(abs(diag(D) - 1))  ;
    v          = V(:, Index)            ;
    piRow      = real((v / sum(v)).')   ;
    piRow      = max(piRow, 0)          ;
    piRow      = piRow / sum(piRow)     ;
end

function [States, Observations] = simulateHMM_K(N, piRow, TransitionMatrix, Means, Sigma)
    nStates      = numel(Means);
    States       = zeros(N, 1) ;
    Observations = zeros(N, 1) ;

    States      (1) = sampleCategorical(piRow)      ;
    Observations(1) = Means(States(1)) + Sigma*randn;

    for              n  = 2 : N
        States      (n) = sampleCategorical(TransitionMatrix(States(n-1), :));
        Observations(n) = Means(States(n)) + Sigma*randn                     ;
    end
end

function Index  = sampleCategorical(rowProb)
         cumSum = cumsum(rowProb(:).')            ;
         Index  = find(rand <= cumSum, 1, "First");
    if isempty(Index);    Index = numel(rowProb)  ;    end
end

function tIndex = geometricTimes(N, Probability)
% Return Retained Observation Schedule for Exactly N Recorded Observations.
% By construction, t1 = 1 and, for n >= 2, gn = t_n - t_{n-1} is geometric on {1,2,...} with mean 1/Probability.
    if Probability <= 0 || Probability > 1;    error('geometricTimes:BadProbability', 'Probability must lie in (0,1].');    end
    if N < 1;    error('geometricTimes:BadN', 'N Must Be at Least 1.');    end

    tIndex = ones(N, 1);
    if N  == 1;    return;    end

    U               = rand(N - 1, 1);
    g               = 1 + floor(log(1 - U) ./ log(1 - Probability));
    tIndex(2 : end) = 1 + cumsum(g);
end

function [Starts, Ends] = scheduleSegments(timeIndex)
% Return Maximal Runs with diff(timeIndex) == 1.
% A New Segment Begins Whenever at Least One Observation is Missing.
  timeIndex = timeIndex(:).';
  if isempty(timeIndex)     ;  Starts = [];  Ends = [];  return;    end

  Breaks = find(diff(timeIndex) > 1) ;
  Starts = [1, Breaks + 1]           ;
  Ends   = [Breaks, numel(timeIndex)];
end

function U     = simulateIndependentTraces(Lengths, piRow, TransitionMatrix, Means, Sigma)
% Simulate Genuinely Independent Traces with the Same Observed Segment Lengths.
  nSegments  = numel(Lengths)    ;
  U          = cell(nSegments, 1);
  for     k  = 1 : nSegments
    [~, u]   = simulateHMM_K(Lengths(k), piRow, TransitionMatrix, Means, Sigma);
        U{k} = u(:).'                                                          ;
  end
end

function logL = forwardAnalytic(w, timeIndex, piRow, TransitionMatrix, EmissionModel)
% Exact Forward Recursion Using the Analytic Bridge (TransitionMatrix^g) Across Each Gap.
    w         = w(:)          ;
    timeIndex = timeIndex(:).';
    N         = numel(w)      ;
    nStates   = numel(piRow)  ;

    deltas    = [0, diff(timeIndex)];
    uniqD     = unique(deltas);
    Bridge    = containers.Map('KeyType','double', 'ValueType','any');
    for j     = 1 : numel(uniqD)
        d     = uniqD(j);
        if d == 0;    Bridge(d) = eye(nStates)      ;
        else     ;    Bridge(d) = TransitionMatrix^d;
        end
    end

    FilteringDistribution = piRow;
    cumSum  = 0 ;
    for n = 1 : N
        FilteringDistribution = FilteringDistribution * Bridge(deltas(n))   ;
        EmissionMatrix  = arrayfun(@(s) EmissionModel(w(n), s), 1 : nStates);
        un    = FilteringDistribution .* EmissionMatrix                     ;
        Z     = sum(un)                                                     ;

        if ~(isfinite(Z) && Z > 0)
            logL = -Inf;
            return
        end

        FilteringDistribution = un / Z;
        cumSum  = cumSum + log(Z);
    end

    logL = cumSum;
end

function logL = forwardStationary(w, timeIndex, TransitionMatrix, EmissionModel)
% Break the Retained Trace at Every Missing Interval.
% Restart Each Observed Segment from StationaryDistribution(TransitionMatrix).
    w         = w(:)                     ;
    timeIndex = timeIndex(:).'           ;
    nStates   = size(TransitionMatrix, 1);

    if isempty(w);    logL = 0;    return;    end

    StationaryDistribution = getStationaryDistribution(TransitionMatrix);
    [Starts, Ends]         = scheduleSegments(timeIndex)                ;

    cumSum = 0 ;
    for k  = 1 : numel(Starts)
        a  = Starts(k);
        b  = Ends(k)  ;

        FilteringDistribution = StationaryDistribution;

        for    n = a : b
            if n > a ;    FilteringDistribution = FilteringDistribution * TransitionMatrix;    end

            EmissionMatrix = arrayfun(@(s) EmissionModel(w(n), s), 1 : nStates);
            un             = FilteringDistribution .* EmissionMatrix           ;
            Z              = sum(un)                                           ;

            if ~(isfinite(Z) && Z > 0);    logL = -Inf;    return;    end

            FilteringDistribution = un / Z         ;
            cumSum                = cumSum + log(Z);
        end
    end
    logL = cumSum;
end

function logL = forwardIndependent(uChunks, TransitionMatrix, EmissionModel)
% Factorized Likelihood for Genuinely Independent Traces Analyzed Jointly.
    nStates = size(TransitionMatrix, 1)                  ;
    rho     = getStationaryDistribution(TransitionMatrix);
    cumSum  = 0                                          ;

    for k                     = 1 : numel(uChunks)
        u                     = uChunks{k}(:);
        FilteringDistribution = rho          ;

        for n = 1 : numel(u)
            if n > 1;    FilteringDistribution = FilteringDistribution * TransitionMatrix;    end

            EmissionMatrix = arrayfun(@(s) EmissionModel(u(n), s), 1:nStates);
            un             = FilteringDistribution .* EmissionMatrix         ;
            Z              = sum(un)                                         ;

            if ~(isfinite(Z) && Z > 0);    logL = -Inf;    return;    end

            FilteringDistribution = un / Z         ;
            cumSum                = cumSum + log(Z);
        end
    end
    logL = cumSum;
end

function p = normalizeLogVector(logV, x)
% Normalize a 1-Dimensional log(Density) Such That It Integrates to Unity.
    isFinite = isfinite(logV);
    if~any(isFinite);    error('normalizeLogVector:NoFiniteValues', 'No Finite logPosterior Values Found on Grid.');    end

    Shift         = max(logV(isFinite))      ;
    v             = zeros(size(logV))        ;
    v(isFinite) = exp(logV(isFinite) - Shift);

    Z = trapz(x, v)          ;
    if~(isfinite(Z) && Z > 0);    error('normalizeLogVector:BadNormalization', 'Could Not Normalize Posterior Vector!');    end
    p = v / Z;
end

function Observation = pdfGaussian(RandomVariable, Mean, StandardDeviation)
% Normal Distribution Parameterized by σ.
         w           = (RandomVariable - Mean) / StandardDeviation            ;
         Observation = exp(-0.5 * w .* w) / (sqrt(2 * pi) * StandardDeviation);
end

